// Extract client company domains from connections response
const items = $input.all();
const clients = [];

for (const item of items) {
  const connections = item.json.data || item.json.connections || [];
  const competitorDomain = item.json.domain || $('🔄 Loop Competitors').item.json.domain || 'unknown';

  for (const conn of connections) {
    const attrs = conn.attributes || conn;
    const relationType = (attrs.connection_type || attrs.relationship_type || attrs.type || '').toLowerCase();

    // Include client relationships, or if no type filter, include all connections
    if (
      relationType.includes('client') ||
      relationType.includes('customer') ||
      relationType.includes('user') ||
      relationType === ''
    ) {
      const clientDomain = attrs.domain || attrs.company_domain || attrs.connected_company_domain || null;
      if (clientDomain) {
        clients.push({
          json: {
            competitor_source: competitorDomain,
            client_domain: clientDomain,
            relationship_type: relationType || 'connection'
          }
        });
      }
    }
  }
}

// If no clients found, pass empty marker
if (clients.length === 0) {
  return [{ json: { _no_clients: true, competitor_source: 'N/A' } }];
}

return clients;

// Format enriched client data into output row
const item = $input.first();
const companyData = item.json.data?.attributes || item.json.attributes || item.json;

// Get competitor source from the Loop Clients context
const competitorSource = $('🔄 Loop Clients').item.json.competitor_source || 'unknown';
const clientDomain = $('🔄 Loop Clients').item.json.client_domain || item.json.domain || 'unknown';

return [{
  json: {
    competitor_source: competitorSource,
    client_domain: clientDomain,
    client_name: companyData.company_name || companyData.name || clientDomain,
    industry: companyData.industry || companyData.sector || 'Unknown',
    employee_count: companyData.employee_count || companyData.employees || 'Unknown',
    location: [
      companyData.city,
      companyData.state,
      companyData.country
    ].filter(Boolean).join(', ') || 'Unknown'
  }
}];
